// Instead of THIS (relational, normalized):
//
//   users: [{ id: 1, name: 'Ada', email: 'ada@x.com' }]
//   addresses: [{ id: 100, user_id: 1, street: '...', city: '...' }]
//   orders: [{ id: 500, user_id: 1, total: 42.99 }]
//
// MongoDB embraces THIS (denormalized, nested):

{
  _id: ObjectId('...'),
  email: 'ada@x.com',
  name: 'Ada Lovelace',
  addresses: [                        // array of embedded sub-documents
    { type: 'home',    street: '123 Main St',   city: 'London',   postcode: 'SW1' },
    { type: 'billing', street: '10 Downing St', city: 'London',   postcode: 'SW1A' }
  ],
  preferences: {                       // nested object
    theme: 'dark',
    notifications: { email: true, sms: false }
  },
  recent_orders: [                     // recent activity — embedded (if small)
    { order_id: ObjectId('...'), total: 42.99, date: ISODate('2026-07-01T...') },
    { order_id: ObjectId('...'), total: 18.50, date: ISODate('2026-06-28T...') }
  ],
  tags: ['premium', 'verified'],       // array of strings
  created_at: ISODate('2024-01-15T...'),
  updated_at: ISODate('2026-07-02T...')
}

// Fetching this user = ONE query. No JOINs. Fast.
// But: what if 'recent_orders' grows to 10,000? Documents cap at 16MB.
// AND: what if you also want to query 'all orders for user 42' independently?
//
// Rule: EMBED when the child is always read WITH the parent AND is bounded in size.
// REFERENCE (store just an ObjectId) when the child is queried independently OR unbounded.

// Insert
db.users.insertOne({
  email: 'ada@x.com', name: 'Ada Lovelace',
  tags: ['premium'], created_at: new Date()
});

db.users.insertMany([
  { email: 'ben@x.com', name: 'Ben' },
  { email: 'cara@x.com', name: 'Cara' }
]);

// Find — query is a JSON document describing conditions
db.users.find({ tags: 'premium' });                                  // has 'premium' tag
db.users.find({ age: { $gte: 18, $lt: 65 } });                       // range
db.users.find({ $or: [{ role: 'admin' }, { verified: true }] });     // OR
db.users.find({ 'preferences.theme': 'dark' });                      // dot notation for nested
db.users.find({ tags: { $all: ['premium', 'verified'] } });          // all-of array

// Projection — return only some fields
db.users.find({ tags: 'premium' }, { name: 1, email: 1, _id: 0 });

// Update
db.users.updateOne(
  { _id: ObjectId('...') },
  { $set: { name: 'Ada L.' }, $push: { tags: 'vip' }, $currentDate: { updated_at: true } }
);

// Delete
db.orders.deleteMany({ status: 'CANCELLED', created_at: { $lt: cutoffDate } });

// ============ AGGREGATION PIPELINE — the big one ============
// Stages transform documents step-by-step, like Unix pipes.
db.orders.aggregate([
  // Stage 1: filter
  { $match: { status: 'PAID', created_at: { $gte: ISODate('2026-01-01') } } },

  // Stage 2: group by user_id, sum totals
  { $group: {
      _id: '$user_id',
      total_spent: { $sum: '$total' },
      order_count: { $count: {} },
      last_order:  { $max: '$created_at' }
  }},

  // Stage 3: enrich with user info (like a JOIN)
  { $lookup: {
      from: 'users',
      localField: '_id',
      foreignField: '_id',
      as: 'user'
  }},
  { $unwind: '$user' },

  // Stage 4: shape the output
  { $project: {
      _id: 0,
      user_id: '$_id',
      name: '$user.name',
      email: '$user.email',
      total_spent: 1,
      order_count: 1,
      last_order: 1
  }},

  // Stage 5: sort + limit
  { $sort: { total_spent: -1 } },
  { $limit: 10 }
]);
// = 'top 10 users by total spent in 2026, with their info'

// Create indexes — same principles as SQL
db.users.createIndex({ email: 1 }, { unique: true });
db.orders.createIndex({ user_id: 1, created_at: -1 });
db.users.createIndex({ 'preferences.theme': 1 });     // nested field
db.users.createIndex({ tags: 1 });                     // array (multikey index)
